@tool
def send_email(to: str, subject: str, body: str, idempotency_key: str) -> Result:
    if seen(idempotency_key):
        return cached_result(idempotency_key)
    result = email_provider.send(to, subject, body)
    store(idempotency_key, result)
    return result
